function reverseNum(num) {
  let reversed = 0, n = Math.abs(num);
  while (n > 0) {
    reversed = reversed * 10 + n % 10;
    n = Math.floor(n / 10);
  }
  return num < 0 ? -reversed : reversed;
}

function reverseNumRecursive(num, rev = 0) {
  if (Math.abs(num) < 10) return num * Math.sign(num) + rev * 10;
  return reverseNumRecursive(
    Math.floor(Math.abs(num) / 10),
    rev * 10 + num % 10
  );
}
